class MyQueue {
    private java.util.Stack<Integer> stackNewestOnTop;
    private java.util.Stack<Integer> stackOldestOnTop;

    public MyQueue() {
        stackNewestOnTop = new java.util.Stack<>();
        stackOldestOnTop = new java.util.Stack<>();
    }

    public void push(int x) {
        stackNewestOnTop.push(x);
    }

    public int pop() {
        shiftStacks();
        return stackOldestOnTop.pop();
    }

    public int peek() {
        shiftStacks();
        return stackOldestOnTop.peek();
    }

    public boolean empty() {
        return stackNewestOnTop.isEmpty() && stackOldestOnTop.isEmpty();
    }

    private void shiftStacks() {
        if (stackOldestOnTop.isEmpty()) {
            while (!stackNewestOnTop.isEmpty()) {
                stackOldestOnTop.push(stackNewestOnTop.pop());
            }
        }
    }
}
